SELECT id, webhook_name, webhook_url, event_types, status, retry_count, timeout_seconds, created_time, updated_time FROM sys_webhook_config WHERE deleted = FALSE
AND webhook_name LIKE CONCAT('%', #{query.webhookName}, '%')
AND status = #{query.status}
ORDER BY created_time DESC LIMIT #{query.pageSize} OFFSET #{query.pageNum} * #{query.pageSize} - #{query.pageSize}

SELECT COUNT(*) FROM sys_webhook_config WHERE deleted = FALSE
AND webhook_name LIKE CONCAT('%', #{query.webhookName}, '%')
AND status = #{query.status}
